#include <iostream>
#include <cmath>
using namespace std;

int main() {
  int a = 10, b = 3;
  double x = 5.5, y = 2.0;

  cout << "Integer division: " << (a / b) << endl;
  cout << "Double division: " << (x / y) << endl;
  cout << "Power: " << pow(2, 5) << endl;
  cout << "Square root: " << sqrt(25) << endl;
  return 0;
}
